rules.pseudocode:
# Collect values for all actions:
# V[eat], V[move_up], V[move_down], V[move_left], V[move_right], V[stay]
values = {a: V_a for a, V_a in action_values.items()}
max_v = max(values.values())
exp_vals = {a: exp(beta * (v - max_v)) for a, v in values.items()}
total = sum(exp_vals.values())
probs = {a: e / total for a, e in exp_vals.items()}
selected = sample_from(probs)
